const meta = {
  phase: "ONTOLOGY-01B",
  tier: 1,
  description: "Tier 1 launch wine regions — editorial catalog SSOT for region pages and knowledge graph edges.",
};

function validateDescriptors(taxonomy, regionList) {
  const errors = [];
  for (const r of regionList) {
    for (const slug of r.typical_descriptors ?? []) {
      const node = taxonomy.nodes[slug];
      if (!node || (node.type !== "descriptor" && node.entity_type !== "descriptor")) {
        errors.push(`${r.slug}: unknown descriptor "${slug}"`);
      }
    }
  }
  return errors;
}

function main() {
  const taxonomy = JSON.parse(fs.readFileSync(TAXONOMY_PATH, "utf8"));
  const descriptorErrors = validateDescriptors(taxonomy, regions);

  if (descriptorErrors.length) {
    console.error("Descriptor validation failed:");
    for (const err of descriptorErrors) console.error(`  ✗ ${err}`);
    process.exit(1);
  }

  fs.writeFileSync(OUT, JSON.stringify({ meta, regions }, null, 2) + "\n");

  const slugs = regions.map((r) => r.slug);
  console.log(`Wrote ${regions.length} wine regions to ${OUT}`);
  console.log(`Slugs: ${slugs.join(", ")}`);
  console.log(`✓ All typical_descriptors validated against wine-taxonomy.json`);
}

main();
